// parse_ethernet状态
state parse_ethernet {
  packet.extract(hdr.ethernet);
  transition select(hdr.ethernet.etherType){
    TYPE_IPV4: parse_ipv4;
    TYPE_SOURCE_ROUTING: parse_source_routing;
    default: accept;
  }
